VALUES
  ('real-estate-moex-00928', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲乙是大四同班同學，甲平常騎乘其父丙所贈與之電動機車作為交通工具。某日乙向甲借用該部電 動機車，以接送其高中同學到學校所在地之風景名勝地區遊玩。下列有關甲乙間之契約關係的敘述 何者錯誤？ 甲乙間所訂立之契約為單務契約，乙之返還義務與甲之容忍使用義務間，無同時履行抗辯權之適用 甲乙間所訂立之契約為要物契約，以物之交付為契約成立之特別要件，必待借用物之交付，契約 始得成立 甲乙間所訂立之契約為使用借貸契約，乙非經甲之同意，不得允許第三人使用該借用物，否則甲 得終止契約 甲乙間所訂立之契約為使用借貸契約，甲對乙不以故意不告知借用物之瑕疵為限，承擔瑕疵擔保 的責任，乙因此瑕疵所受之損害，得向甲請求賠償', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00929', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於繼承之效力，下列敘述何者錯誤？ 繼承人對於被繼承人之債務，以因繼承所得遺產為限，負清償責任 繼承，因被繼承人死亡而開始 繼承人有數人時，在分割遺產前，各繼承人對於遺產全部為公同共有 繼承人從被繼承人生前所受贈之全部財產，視為其所得遺產', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00930', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於意思表示錯誤，下列敘述何者正確？ 當事人資格之錯誤，可能得撤銷之  表意人得向相對人請求損害賠償 動機錯誤，均為意思表示內容之錯誤  表示行為錯誤，不得撤銷', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00931', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲有A地，且登記為A地所有人。甲因乙之脅迫，出賣且交付A地於乙，於甲尚未撤銷買賣契約前。 試問，下列敘述何者正確？ 甲得撤銷交付A地於乙之行為  現占有A地之乙為有權占有人 乙因此成為A地所有人  甲乙間之A地的買賣契約，無效', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00932', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於消滅時效，下列敘述何者正確？ 消滅時效之規定，已登記不動產之回復請求權，亦有適用 一般消滅時效期間，乃20年 請求權因其消滅時效完成而消滅 以租賃動產為營業者之租價請求權，其消滅時效期間為2年', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00933', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依民法規定，關於不動產買賣，下列敘述何者正確？ 應作成公證書    非經登記，不生效力 非經交付買賣之不動產，不生效力  因當事人就標的物及其價金互相同意而成立', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00934', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲有A屋，登記為A屋所有人。甲將A屋贈與乙女。試問，下列敘述何者正確？ 非經交付A屋，該贈與不生效力  該贈與應以書面為之 甲移轉A屋所有權予乙前，得撤銷該贈與  甲遲延交付A屋予乙時，乙得請求遲延損害賠償', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00935', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依民法規定，關於受任人之權利及義務，下列敘述何者正確？ 受任人受有報酬者，應以善良管理人之注意，處理委任事務 受任人未處理委任事務前，不得向委任人請求預付處理委任事務之必要費用 受任人必有代理權 受任人不得隨時終止委任契約', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00936', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲有A屋，共95坪，登記為A屋所有人。乙詢問甲A屋坪數，甲告知A屋計有100坪。甲與乙締 結100坪之A屋買賣契約。試問，下列敘述何者錯誤？ 甲侵害乙之A屋所有權 乙得解除契約 乙得請求減少價金 乙得以甲詐欺為由，撤銷締結該買賣契約之意思表示', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00937', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲有A地，登記為A地所有人。甲與乙成立承攬契約，由乙承攬A地之整地工作。乙不僅整地有瑕 疵，而且還趁整地之餘，將有毒廢棄物掩埋於A地之下。試問，下列敘述何者錯誤？ 甲得請求乙修補瑕疵 甲依侵權行為法之規定（民法第184條第1項前半段），得請求乙回復原狀，移除掩埋在A地下 之有毒廢棄物 甲得以掩埋有毒廢棄物乃違反保護義務為由，解除契約 甲得依民法第495條第1項規定，請求乙賠償A地因掩埋有毒廢棄物所減損之價額', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00938', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於遺囑，下列敘述何者正確？ 遺囑乃非要式行為 無行為能力人，僅得為公證遺囑 代筆遺囑，應由遺囑人指定二人以上之見證人 繼承人及其配偶或其直系血親，不得為遺囑見證人', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00939', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲對乙負有1,000萬元借款債務，丙為甲對乙所負該債務之連帶保證人。試問，下列敘述何者正確？ 乙得直接請求丙履行1,000萬元保證債務  乙僅得同時請求甲與丙履行債務 丙連帶責任之約定無效  丙負最終責任', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00940', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於合會，下列敘述何者正確？ 法人亦得為合會會員   會首得兼為同一合會之會員 限制行為能力人亦得為會員  自然人不得同時為數合會之會首', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00941', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於物權法定主義，下列敘述何者正確？ 僅得依制定法創設物權  僅得依特別法創設物權 得依習慣法創設物權   得依法理創設物權', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
